import{E as e,R as t,_ as n,h as r,pt as i,x as a,z as o}from"./runtime-core.esm-bundler-zlLwmkyI.js";var s={class:`ant-doc vp-doc`},c=a({__name:`skills.zh-CN`,setup(a,{expose:c}){let l={title:`技能`,frontmatter:{title:`技能`,tag:`New`},headers:[{level:2,title:`什么是 Agent Skills？`,slug:`什么是-agent-skills`,link:`#什么是-agent-skills`,children:[{level:3,title:`为什么使用 ProComponents of Vuents of Vue Skills？`,slug:`为什么使用-procomponents-of-vuents-of-vue-skills`,link:`#为什么使用-procomponents-of-vuents-of-vue-skills`,children:[]}]},{level:2,title:`Skills 如何工作`,slug:`skills-如何工作`,link:`#skills-如何工作`,children:[{level:3,title:`三级加载机制`,slug:`三级加载机制`,link:`#三级加载机制`,children:[]}]},{level:2,title:`安装`,slug:`安装`,link:`#安装`,children:[]},{level:2,title:`使用方法`,slug:`使用方法`,link:`#使用方法`,children:[{level:3,title:`使用示例`,slug:`使用示例`,link:`#使用示例`,children:[]}]},{level:2,title:`技术实现`,slug:`技术实现`,link:`#技术实现`,children:[{level:3,title:`Skill 结构`,slug:`skill-结构`,link:`#skill-结构`,children:[]},{level:3,title:`生成流程`,slug:`生成流程`,link:`#生成流程`,children:[]}]},{level:2,title:`支持的AI平台`,slug:`支持的ai平台`,link:`#支持的ai平台`,children:[]},{level:2,title:`贡献`,slug:`贡献`,link:`#贡献`,children:[]}],description:``},u={title:`技能`,tag:`New`},d=i({});o(`__pageData__`,e=>{d.value=e});let f=e(`__pageData__`,null);return f&&f(l),o(`__pageInfo__`,l),c({frontmatter:u,pageData:l}),(e,i)=>(t(),r(`div`,s,[...i[0]||=[n(`<p>Agent Skills 是扩展 AI 功能的模块化能力。ProComponents of Vue Skills 为 AI Agent 提供 ProComponents of Vue 组件库的专业知识，让 AI 能够准确理解和使用组件。</p><h2 id="什么是-agent-skills" tabindex="-1">什么是 Agent Skills？ <a class="header-anchor" href="#什么是-agent-skills" aria-label="Permalink to &quot;什么是 Agent Skills？&quot;">​</a></h2><p>Agent Skills 是可重用的、基于文件系统的资源，为 AI Agent 提供特定领域的专业知识：工作流、上下文和最佳实践，将通用代理转变为专家。与提示不同（提示是对话级别的一次性任务指令），<strong>Skills 按需加载，无需在多个对话中重复提供相同的指导</strong>。</p><h3 id="为什么使用-procomponents-of-vuents-of-vue-skills" tabindex="-1">为什么使用 ProComponents of Vuents of Vue Skills？ <a class="header-anchor" href="#为什么使用-procomponents-of-vuents-of-vue-skills" aria-label="Permalink to &quot;为什么使用 ProComponents of Vuents of Vue Skills？&quot;">​</a></h3><p><strong>主要优势</strong>：</p><ul><li><strong>专业化 AI</strong>：为 ProComponents of Vuents of Vue 组件开发定制功能，让 AI 成为组件库专家</li><li><strong>减少重复</strong>：创建一次，自动使用。无需每次都告诉 AI 如何使用组件</li><li><strong>组合功能</strong>：结合 Skills 构建复杂的组件开发工作流</li><li><strong>减少幻觉</strong>：通过提供真实的文档和示例，避免 AI 生成不存在的 Props 或错误的用法</li><li><strong>离线可用</strong>：Skills 将文档内容本地化，不依赖外部链接，确保稳定可靠</li></ul><h2 id="skills-如何工作" tabindex="-1">Skills 如何工作 <a class="header-anchor" href="#skills-如何工作" aria-label="Permalink to &quot;Skills 如何工作&quot;">​</a></h2><p>Skills 利用 AI Agent 的虚拟机环境提供超越仅使用提示可能实现的功能。AI Agent 在具有文件系统访问权限的虚拟机中运行，允许 Skills 作为包含指令、可执行代码和参考资料的目录存在。</p><p>这种基于文件系统的架构支持<strong>渐进式披露</strong>：AI Agent 按需分阶段加载信息，而不是预先消耗上下文。</p><h3 id="三级加载机制" tabindex="-1">三级加载机制 <a class="header-anchor" href="#三级加载机制" aria-label="Permalink to &quot;三级加载机制&quot;">​</a></h3><p>Skills 可以包含三种类型的内容，每种在不同时间加载：</p><table><thead><tr><th>级别</th><th>加载时间</th><th>令牌成本</th><th>内容</th></tr></thead><tbody><tr><td><strong>第 1 级：元数据</strong></td><td>始终（启动时）</td><td>约 100 个令牌</td><td>YAML 前置数据中的 <code>name</code> 和 <code>description</code></td></tr><tr><td><strong>第 2 级：指令</strong></td><td>触发 Skill 时</td><td>不到 5k 个令牌</td><td>包含指令和指导的 SKILL.md 主体</td></tr><tr><td><strong>第 3 级：资源</strong></td><td>按需</td><td>实际上无限制</td><td>通过 bash 执行的捆绑文件，不将内容加载到上下文中</td></tr></tbody></table><p><strong>这意味着什么？</strong></p><ul><li>AI Agent 启动时只知道「有一个 ProComponents of Vuents of Vue Skill 可以帮助处理组件」</li><li>当你请求「使用 Button 组件」时，AI 才加载 Button 的完整文档</li><li>如果文档引用了示例代码，AI 会按需读取这些文件</li><li>未使用的组件文档不会消耗任何上下文</li></ul><blockquote><p>💡 <strong>类比</strong>：就像为新团队成员准备的入职指南。他们知道指南的存在（元数据），需要时打开相关章节（指令），必要时查看详细附录（资源）。</p></blockquote><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">需要注意的是</p><p>我们建议不要单独食用 ProComponents of Vuents of Vue Skill 配合 <a href="https://github.com/antfu/skills">Antfu Skills 集合</a> 来使用更佳，如果你使用 <code>vue</code> 可以将 <code>vue</code> 的skill以及相关的 <code>skills</code> 全都导入以减少 <code>AI</code> 幻觉，让他的输出更为标准！</p></div><p>通过 Skills CLI 安装 ProComponents of Vuents of Vue 技能集：</p><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">npx</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> skills</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> add</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> antdv-next/skills</span></span></code></pre></div><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><p>安装后，AI Agent 会在与 ProComponents of Vuents of Vue 组件相关的请求中<strong>自动使用</strong> Skills。为了获得最稳定的效果，建议在提示词前显式声明：</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, &lt;你的需求&gt;</span></span></code></pre></div><p>这样可以显式触发技能；否则可能因匹配度不足导致触发不稳定。</p><h3 id="使用示例" tabindex="-1">使用示例 <a class="header-anchor" href="#使用示例" aria-label="Permalink to &quot;使用示例&quot;">​</a></h3><p><strong>基础组件开发</strong>：</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, 创建一个包含表单验证的登录页面</span></span></code></pre></div><p><strong>复杂交互</strong>：</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, 实现一个带搜索、分页和筛选功能的数据表格</span></span></code></pre></div><p><strong>组件定制</strong>：</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, 根据 AGENTS.md 规范重构 Button 组件，确保 Props/Emits/Slots 定义正确</span></span></code></pre></div><p><strong>问题诊断</strong>：</p><div class="language- ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span>use antdv-next skill, 为什么我的 Form 组件验证不生效？</span></span></code></pre></div><h2 id="技术实现" tabindex="-1">技术实现 <a class="header-anchor" href="#技术实现" aria-label="Permalink to &quot;技术实现&quot;">​</a></h2><h3 id="skill-结构" tabindex="-1">Skill 结构 <a class="header-anchor" href="#skill-结构" aria-label="Permalink to &quot;Skill 结构&quot;">​</a></h3><p>ProComponents of Vuents of Vue Skills 遵循标准 Skill 结构：</p><div class="language-yaml ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">---</span></span>
<span class="line"><span style="--ant-doc-light:#998418;--ant-doc-dark:#B8A965;">name</span><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">:</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> antdv-next</span></span>
<span class="line"><span style="--ant-doc-light:#998418;--ant-doc-dark:#B8A965;">description</span><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">:</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> ProComponents of Vuents of Vue 组件库开发专家...</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;"># ProComponents of Vuents of Vue 组件开发</span></span>
<span class="line"></span>
<span class="line"><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">## 快速开始</span></span>
<span class="line"><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">[</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;">组件开发工作流</span><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">## API 约定</span></span>
<span class="line"><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">[</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;">Props/Emits/Slots 规范</span><span style="--ant-doc-light:#999999;--ant-doc-dark:#666666;">]</span></span>
<span class="line"></span>
<span class="line"><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">## 示例</span></span>
<span class="line"><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;">有关具体组件用法，请参阅 [references/components/](references/components/)</span></span></code></pre></div><h3 id="生成流程" tabindex="-1">生成流程 <a class="header-anchor" href="#生成流程" aria-label="Permalink to &quot;生成流程&quot;">​</a></h3><ol><li><strong>文档提取</strong>：从 playground 提取组件文档的 markdown 文件</li><li><strong>示例转换</strong>：将 Vue SFC 示例转换为 markdown 格式</li><li><strong>内容聚合</strong>：将文档和示例复制到 <code>references/</code> 目录</li><li><strong>元数据生成</strong>：创建 YAML 前置数据和主指令</li><li><strong>离线优化</strong>：确保所有内容离线可用，不依赖外部链接</li></ol><p>生成脚本支持单语言输出，以减少 Skill 体积：</p><div class="language-bash ant-code-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes vitesse-light vitesse-dark ant-doc-code"><code><span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> run</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> generate:en</span><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">  # 生成英文版本</span></span>
<span class="line"><span style="--ant-doc-light:#59873A;--ant-doc-dark:#80A665;">pnpm</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> run</span><span style="--ant-doc-light:#B56959;--ant-doc-dark:#C98A7D;"> generate:zh</span><span style="--ant-doc-light:#A0ADA0;--ant-doc-dark:#758575DD;">  # 生成中文版本</span></span></code></pre></div><h2 id="支持的ai平台" tabindex="-1">支持的AI平台 <a class="header-anchor" href="#支持的ai平台" aria-label="Permalink to &quot;支持的AI平台&quot;">​</a></h2><p>ProComponents of Vuents of Vue Skills 作为<strong>自定义 Skills</strong> 可在多个 AI 平台使用：</p><ol><li>Claude Code</li><li>Codex</li><li>Github Copilot</li><li>Cusor</li><li>Antigravity</li><li>…</li></ol><h2 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to &quot;贡献&quot;">​</a></h2><p>该项目是一个<strong>早期实验</strong>，旨在为 AI Agent 提供面向 ProComponents of Vuents of Vue 的专用技能。欢迎通过 <a href="https://github.com/antdv-next/skills/issues">GitHub Issues</a> 提供反馈，帮助我们提升覆盖范围与准确性。</p>`,45)]]))}});export{c as default};